#include <bits/stdc++.h>
#define MAX (100000 + 7)
#define int long long
using namespace std;
int N, k, a[MAX];
long l, r, ans1 = -1, ans2 = -1;
long work(long im) {
    int ans = 0;
	int sum = 0;
    for (int i = 1; i <= N; i++) {
        sum = max(sum + a[i], 0ll);
        if (sum >= im) sum = 0, ans++;
    }
	return ans;
}
signed main() {
	cin >> N >> k;
    for (int i = 1; i <= N; i++) {
    	cin >> a[i];
    }
    l = 1, r = 1e18;
    while (l <= r) {
        int mid = (l + r) >> 1;
        if (work(mid) <= k) {
        	r = mid - 1;
        	if (work(mid) == k) {
        		ans1 = mid;
			}
		} else {
			l = mid + 1;
		}
	}
    l = 1, r = 1e18; 
    while (l <= r)
    {
        int mid = (l + r) >> 1;
        if (work(mid) >= k) {
        	l = mid + 1;
        	if (work(mid) == k) {
        		ans2 = mid;
			}
		} else {
			r = mid - 1;
		}
    }
    if (ans1 == -1) {
    	cout << -1;
	} else {
		cout << ans1 << ' ' << ans2;
	}
	return 0;
}
